def sort_machines(lst, df_ref=None):
    counts = df_ref["機種名"].value_counts().to_dict() if df_ref is not None else {}
    pm = {m: i for i, m in enumerate(MACHINE_PRIORITY)}
    return sorted(lst, key=lambda m: (0, pm[m], 0) if m in pm else (1, 0, -counts.get(m, 0)))

